import { Auth } from '@/store/_auth';
import type { Job } from '@/types';
import { Alert } from 'antd';
import { useMemo } from 'react';
import { useSelector } from 'react-redux';
import { Link } from 'react-router-dom';

const CAPTCHA_FAILURES = [
  'HTTPError: 403 Client Error: Forbidden for url',
  'RuntimeError: Browser is disabled',
];

export const JobErrorDetailsCard: React.FC<{ job: Job }> = ({ job }) => {
  const isAdmin = useSelector(Auth.select.isAdmin);

  const html = useMemo(() => {
    const lines = String(job.error)
      .split('\n')
      .filter(Boolean)
      .map((line) => line.replace(/^\s+/, '&nbsp;'));
    if (isAdmin) {
      return lines.join('<br/>');
    } else if (lines.length > 0) {
      return lines[lines.length - 1];
    }
    return 'Unknown error';
  }, [job.error, isAdmin]);

  const hasCaptchaFailure = useMemo(() => {
    return CAPTCHA_FAILURES.some((failure) =>
      String(job.error).includes(failure)
    );
  }, [job.error]);

  if (!job.error) {
    return null;
  }

  return (
    <div style={{ margin: '15px 0' }}>
      <pre
        style={{
          fontSize: '0.775rem',
          maxHeight: 300,
          margin: 0,
          marginBottom: 10,
          padding: '10px 20px',
          whiteSpace: 'nowrap',
          overflow: 'auto',
          color: '#f8f749',
          border: '1px solid #f8f749',
          background: '#f8f74910',
          borderRadius: 7,
        }}
        dangerouslySetInnerHTML={{ __html: html }}
      />
      {hasCaptchaFailure && (
        <div style={{ margin: '15px 0' }}>
          <Alert
            type="warning"
            title={
              <>
                This issue is caused by Cloudflare captcha challenge, which
                cannot be bypassed by our automated crawler. Please try
                searching for your novel on{' '}
                <Link to="/meta/sources?tab=used">other available sources</Link>{' '}
                that are functioning properly.
              </>
            }
          />
        </div>
      )}
    </div>
  );
};
